using System;

namespace TestProject.Models;

/// <summary>
/// Represents a single file or directory entry returned from browsing or searching.
/// </summary>
public sealed record FileEntryDto(string Name, string Path, bool IsDirectory, long Size, DateTime LastModified, int ItemCount);

using System;
using System.Collections.Generic;

namespace TestProject.Models;

/// <summary>
/// Represents the result of browsing a directory, including its contents and summary counts.
/// </summary>
public sealed record BrowseResultDto(string Path, string? Parent, IReadOnlyList<FileEntryDto> Entries, int FolderCount, int FileCount, long TotalSize);

using System.Collections.Generic;

namespace TestProject.Models;

/// <summary>
/// Represents the result of a search query, containing matching file entries.
/// </summary>
public sealed record SearchResultDto(string Query, string Path, IReadOnlyList<FileEntryDto> Results);

namespace TestProject.Models;

/// <summary>
/// Represents a request to move a file or directory from one location to another.
/// </summary>
public sealed record MoveRequest(string SourcePath, string DestinationPath);

namespace TestProject.Models;

/// <summary>
/// Represents a request to copy a file or directory from one location to another.
/// </summary>
public sealed record CopyRequest(string SourcePath, string DestinationPath);
